  _load() {
    let buffer = '';

    if (!this.path) {
      process.nextTick(() => {
        this.emit('load', 0);
      });
      return;
    }

    this._readStream = fs.createReadStream(this.path, {
      encoding: 'utf-8',
      flags: 'r',
    });

    this._readStream
        .on('error', (err) => {
          if (err.code === 'ENOENT') {
            this.emit('load', 0);
            return;
          }

          this.emit('error', err);
        })
        .on('data', (chunk) => {
          buffer += chunk;
          if (chunk.lastIndexOf('\n') === -1) return;
          const arr = buffer.split('\n');
          buffer = arr.pop();
